+    let selected = next.selected_keys.clone();
+    TransitionPlan::context_only(move |ctx: &mut Context| {
+        ctx.selection.set(selected.clone());
+        ctx.selection_state = next;
+        ctx.selection_state.selected_keys = ctx.selection.get().clone();
+    })
