+        }
+        selection::Set::All => selection::Set::All,
+        _ => selection::Set::Empty,
+    }
+}
+
+fn valid_highlight(ctx: &Context) -> Option<&Key> {
+    ctx.highlighted_key
+        .as_ref()
+        .filter(|key| ctx.items.contains_key(key) && is_focusable_key(ctx, key))
+}
