        attrs.set(HtmlAttr::Aria(AriaAttr::LabelledBy), self.ctx.ids.part("label"));
        if let Some(k) = &self.ctx.highlighted_key {
            attrs.set(HtmlAttr::Aria(AriaAttr::ActiveDescendant), self.ctx.ids.item("item", k));
