        attrs.set(HtmlAttr::Aria(AriaAttr::HasPopup), "listbox");
        attrs.set(HtmlAttr::Aria(AriaAttr::AutoComplete), "none");
        attrs.set(
            HtmlAttr::Aria(AriaAttr::Controls),
            self.ctx.ids.part("content"),
